#include<bits/stdc++.h>
using namespace std;
int n,a[5010],f[5010];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        memset(f,0,sizeof(f));
        int flag=1;
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
            if(a[i]<(i-1))
            {
                flag=0;
            }
        }
        if(flag==0)
        {
            printf("0\n");
            continue;
        }
        for(int i=1;i<=n;i++)
        {
            f[i]=(int)(max(i-1,n-i)>=a[1]);
        }
        for(int i=2;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                f[j]*=(i+j-2>=a[i]);
                if(n-j>=a[i])
                {
                    f[j]+=f[j+1];
                    f[j]%=998244353;
                }
            }
        }
        printf("%d\n",f[1]);
    }
    return 0;
}
